  5→namespace CodeXCore.ServiceTree
  6→{
  7→    using System;
  8→    using System.Collections.Concurrent;
  9→    using System.Collections.Generic;
 10→    using System.Data;
 11→    using System.Linq;
 12→    using System.Security.Cryptography;
 13→    using System.Security.Cryptography.X509Certificates;
 14→    using System.Text;
 15→    using System.Threading;
 16→    using System.Threading.Tasks;
 17→    using global::Azure.Core;
 18→    using global::Azure.Identity;
 19→    using global::Kusto.Data;
 20→    using global::Kusto.Data.Common;
 21→    using global::Kusto.Data.Net.Client;
 22→    using ISExpAuthToolkit;
 23→    using ISExpAuthToolkit.Credential;
 24→    using Microsoft.Extensions.Logging;
 25→
 26→#pragma warning disable CA1303 // Log messages are not localized.
 27→
 28→    /// <summary>
 29→    /// Kusto-backed Service Tree node lookup.
 30→    /// </summary>
 31→    public sealed class ServiceTreeKustoClient : IServiceTreeNodeLookup
 32→    {
 33→        private readonly ServiceTreeKustoOptions kustoOptions;
 34→        private readonly ServiceTreeClientOptions authOptions;
 35→        private readonly ILogger<ServiceTreeKustoClient> logger;
 36→        private readonly TokenCredential? tokenCredential;
 37→        private readonly string tokenScope;
 38→        private readonly bool isConfigured;
 39→        private readonly int maxBatchSize;
 40→        private readonly int maxConcurrency = 4;
 41→
 42→        /// <summary>
 43→        /// Initializes a new instance of the <see cref="ServiceTreeKustoClient"/> class.
 44→        /// </summary>
 45→        /// <param name="kustoOptions">Kusto options.</param>
 46→        /// <param name="authOptions">Auth options.</param>
 47→        /// <param name="logger">Logger instance.</param>
 48→        /// <param name="credentialFactory">Optional credential factory for cross-tenant support.</param>
 49→        public ServiceTreeKustoClient(
 50→            ServiceTreeKustoOptions kustoOptions,
 51→            ServiceTreeClientOptions authOptions,
 52→            ILogger<ServiceTreeKustoClient> logger,
 53→            ICredentialFactory credentialFactory = null)
 54→        {
 55→            this.kustoOptions = kustoOptions ?? throw new ArgumentNullException(nameof(kustoOptions));
 56→            this.authOptions = authOptions ?? throw new ArgumentNullException(nameof(authOptions));
 57→            this.logger = logger ?? throw new ArgumentNullException(nameof(logger));
 58→
 59→            if (string.IsNullOrWhiteSpace(this.kustoOptions.ClusterUri)
 60→                || string.IsNullOrWhiteSpace(this.kustoOptions.Database))
 61→            {
 62→                this.logger.LogWarning("ServiceTreeKustoClient: Kusto cluster or database is not configured.");
 63→                this.isConfigured = false;
 64→                return;
 65→            }
 66→
 67→            this.tokenScope = this.ResolveTokenScope(this.kustoOptions);
 68→            if (string.IsNullOrWhiteSpace(this.tokenScope))
 69→            {
 70→                this.logger.LogWarning("ServiceTreeKustoClient: Token scope is not configured.");
 71→                this.isConfigured = false;
 72→                return;
 73→            }
 74→
 75→            this.tokenCredential = this.ResolveTokenCredential(credentialFactory, this.authOptions);
 76→            if (this.tokenCredential == null)
 77→            {
 78→                this.logger.LogWarning("ServiceTreeKustoClient: No AAD credentials configured for Kusto.");
 79→                this.isConfigured = false;
 80→                return;
 81→            }
 82→
 83→            this.maxBatchSize = this.kustoOptions.MaxBatchSize <= 0 ? 200 : this.kustoOptions.MaxBatchSize;
 84→            this.isConfigured = true;
 85→
 86→            this.logger.LogInformation(
 87→                "ServiceTreeKustoClient: Configured. Cluster={Cluster}, Database={Database}, Table={Table}, CredentialType={CredentialType}, TokenScope={TokenScope}.",
 88→                this.kustoOptions.ClusterUri,
 89→                this.kustoOptions.Database,
 90→                this.kustoOptions.HierarchyTableName,
 91→                this.tokenCredential.GetType().Name,
 92→                this.tokenScope);
 93→        }
 94→
 95→        /// <inheritdoc/>
 96→        public async Task<IReadOnlyDictionary<string, ServiceTreeNode>> GetHierarchyNodesByServiceIdsAsync(
 97→            IEnumerable<string> serviceIds,
 98→            CancellationToken cancellationToken)
 99→        {
100→            var results = new ConcurrentDictionary<string, ServiceTreeNode>(StringComparer.OrdinalIgnoreCase);
101→            if (!this.isConfigured)
102→            {
103→                return results;
104→            }
105→
106→            var uniqueIds = (serviceIds ?? Enumerable.Empty<string>())
107→                .Where(id => !string.IsNullOrWhiteSpace(id))
108→                .Select(id => id.Trim())
109→                .Distinct(StringComparer.OrdinalIgnoreCase)
110→                .ToList();
111→
112→            if (uniqueIds.Count == 0)
113→            {
114→                return results;
115→            }
116→
117→            var batches = this.SplitStringBatches(uniqueIds, this.maxBatchSize);
118→            using var semaphore = new SemaphoreSlim(this.maxConcurrency);
119→            var tasks = batches.Select(async batch =>
120→            {
121→                await semaphore.WaitAsync(cancellationToken);
122→                try
123→                {
124→                    var batchResults = await this.QueryHierarchyBatchAsync(batch, cancellationToken);
125→                    foreach (var pair in batchResults)
126→                    {
127→                        results[pair.Key] = pair.Value;
128→                    }
129→                }
130→                catch (OperationCanceledException)
131→                {
132→                    throw;
133→                }
134→                catch (Exception ex)
135→                {
136→                    this.logger.LogWarning(
137→                        ex,
138→                        "ServiceTreeKustoClient: Batch of {BatchCount} IDs failed; continuing with remaining batches.",
139→                        batch.Count);
140→                }
141→                finally
142→                {
143→                    semaphore.Release();
144→                }
145→            }).ToList();
146→
147→            await Task.WhenAll(tasks);
148→            return results;
149→        }
150→
151→        private static string EscapeKustoString(string value)
152→        {
153→            return value.Replace("'", "''", StringComparison.Ordinal);
154→        }
155→
156→        private async Task<IReadOnlyDictionary<string, ServiceTreeNode>> QueryHierarchyBatchAsync(
157→            IReadOnlyList<string> batch,
158→            CancellationToken cancellationToken)
159→        {
160→            var results = new Dictionary<string, ServiceTreeNode>(StringComparer.OrdinalIgnoreCase);
161→            if (batch.Count == 0)
162→            {
163→                return results;
164→            }
165→
166→            // Build a fast-lookup set of the (already-lowercased) input IDs so we can
167→            // cross-key results by whichever hierarchy column matched each row.
168→            var batchSet = new HashSet<string>(
169→                batch.Select(id => id.ToLowerInvariant()),
170→                StringComparer.OrdinalIgnoreCase);
171→
172→            var hierarchyTable = this.NormalizeIdentifier(this.kustoOptions.HierarchyTableName);
173→            var builder = new StringBuilder();
174→            builder.AppendLine("let ids = datatable(TargetId:string)[");
175→            builder.Append(string.Join(", ", batch.Select(id => $"'{EscapeKustoString(id.ToLowerInvariant())}'")));
176→            builder.AppendLine("];");
177→            builder.AppendLine($"{hierarchyTable}");
178→            builder.AppendLine("| where tolower(ServiceId) in (ids)");
179→            builder.AppendLine("    or tolower(column_ifexists(\"TeamGroupId\", \"\")) in (ids)");
180→            builder.AppendLine("    or tolower(column_ifexists(\"ServiceGroupId\", \"\")) in (ids)");
181→            builder.AppendLine("    or tolower(column_ifexists(\"OrganizationId\", \"\")) in (ids)");
182→            builder.AppendLine("    or tolower(column_ifexists(\"DivisionId\", \"\")) in (ids)");
183→            builder.AppendLine("| project");
184→            builder.AppendLine("    Id = tostring(ServiceId),");
185→            builder.AppendLine("    Name = tostring(column_ifexists(\"ServiceName\", \"\")),");
186→            builder.AppendLine("    Level = tostring(column_ifexists(\"ServiceLevel\", \"\")),");
187→            builder.AppendLine("    TeamGroupId = tostring(column_ifexists(\"TeamGroupId\", \"\")),");
188→            builder.AppendLine("    TeamGroupName = tostring(column_ifexists(\"TeamGroupName\", \"\")),");
189→            builder.AppendLine("    ServiceGroupId = tostring(column_ifexists(\"ServiceGroupId\", \"\")),");
190→            builder.AppendLine("    ServiceGroupName = tostring(column_ifexists(\"ServiceGroupName\", \"\")),");
191→            builder.AppendLine("    OrganizationId = tostring(column_ifexists(\"OrganizationId\", \"\")),");
192→            builder.AppendLine("    OrganizationName = tostring(column_ifexists(\"OrganizationName\", \"\")),");
193→            builder.AppendLine("    DivisionId = tostring(column_ifexists(\"DivisionId\", \"\")),");
194→            builder.AppendLine("    DivisionName = tostring(column_ifexists(\"DivisionName\", \"\"))");
195→            var query = builder.ToString();
196→
197→            var requestProperties = new ClientRequestProperties();
198→            requestProperties.ClientRequestId = $"CodexSite.ServiceTreeHierarchy.{Guid.NewGuid():N}";
199→
200→            try
201→            {
202→                this.logger.LogInformation(
203→                    "ServiceTreeKustoClient: Executing hierarchy query for {BatchCount} IDs against {Cluster}/{Database}/{Table}.",
204→                    batch.Count,
205→                    this.kustoOptions.ClusterUri,
206→                    this.kustoOptions.Database,
207→                    this.kustoOptions.HierarchyTableName);
208→
209→                using var provider = this.CreateQueryProvider();
210→                using var reader = await provider.ExecuteQueryAsync(this.kustoOptions.Database, query, requestProperties);
211→
212→                do
213→                {
214→                    var idOrdinal = this.TryGetOrdinal(reader, "Id");
215→                    if (idOrdinal < 0)
216→                    {
217→                        continue;
218→                    }
219→
220→                    var nameOrdinal = this.TryGetOrdinal(reader, "Name");
221→                    var levelOrdinal = this.TryGetOrdinal(reader, "Level");
222→                    var teamGroupIdOrdinal = this.TryGetOrdinal(reader, "TeamGroupId");
223→                    var serviceGroupIdOrdinal = this.TryGetOrdinal(reader, "ServiceGroupId");
224→                    var serviceGroupNameOrdinal = this.TryGetOrdinal(reader, "ServiceGroupName");
225→                    var organizationIdOrdinal = this.TryGetOrdinal(reader, "OrganizationId");
226→                    var organizationNameOrdinal = this.TryGetOrdinal(reader, "OrganizationName");
227→                    var divisionIdOrdinal = this.TryGetOrdinal(reader, "DivisionId");
228→                    var divisionNameOrdinal = this.TryGetOrdinal(reader, "DivisionName");
229→
230→                    while (reader.Read())
231→                    {
232→                        var id = this.ReadString(reader, idOrdinal);
233→                        if (string.IsNullOrWhiteSpace(id))
234→                        {
235→                            continue;
236→                        }
237→
238→                        var node = new ServiceTreeNode
239→                        {
240→                            Id = id,
241→                            Name = this.ReadString(reader, nameOrdinal),
242→                            Level = this.ReadString(reader, levelOrdinal),
243→                            ServiceGroupId = this.ReadString(reader, serviceGroupIdOrdinal),
244→                            ServiceGroupName = this.ReadString(reader, serviceGroupNameOrdinal),
245→                            OrganizationId = this.ReadString(reader, organizationIdOrdinal),
246→                            OrganizationName = this.ReadString(reader, organizationNameOrdinal),
247→                            DivisionId = this.ReadString(reader, divisionIdOrdinal),
248→                            DivisionName = this.ReadString(reader, divisionNameOrdinal),
249→                        };
250→
251→                        // Always key by the native ServiceId for backward compatibility.
252→                        results[id] = node;
253→
254→                        // Also key by any hierarchy ancestor ID that the caller asked for.
255→                        // This lets a caller who passed an OrganizationId (or ServiceGroupId etc.)
256→                        // find the result via hierarchyResults.TryGetValue(inputId).
257→                        var teamGroupId = this.ReadString(reader, teamGroupIdOrdinal);
258→                        foreach (var hierarchyId in new[]
259→                        {
260→                            teamGroupId,
261→                            node.ServiceGroupId,
262→                            node.OrganizationId,
263→                            node.DivisionId,
264→                        })
265→                        {
266→                            if (!string.IsNullOrWhiteSpace(hierarchyId)
267→                                && batchSet.Contains(hierarchyId.ToLowerInvariant()))
268→                            {
269→                                results[hierarchyId] = node;
270→                            }
271→                        }
272→                    }
273→                }
274→                while (results.Count == 0 && reader.NextResult());
275→
276→                this.logger.LogInformation(
277→                    "ServiceTreeKustoClient: Hierarchy query completed. Returned {ResultCount} results for {BatchCount} input IDs.",
278→                    results.Count,
279→                    batch.Count);
280→            }
281→            catch (OperationCanceledException)
282→            {
283→                throw;
284→            }
285→            catch (Exception ex)
286→            {
287→                this.logger.LogError(
288→                    ex,
289→                    "ServiceTreeKustoClient: hierarchy query failed. Cluster={Cluster}, Database={Database}, Table={Table}, CredentialType={CredentialType}, BatchCount={BatchCount}.",
290→                    this.kustoOptions.ClusterUri,
291→                    this.kustoOptions.Database,
292→                    this.kustoOptions.HierarchyTableName,
293→                    this.tokenCredential?.GetType().Name ?? "null",
294→                    batch.Count);
295→                throw;
296→            }
297→
298→            return results;
299→        }
300→
301→        private ICslQueryProvider CreateQueryProvider()
302→        {
303→            var kcsb = new KustoConnectionStringBuilder(this.kustoOptions.ClusterUri, this.kustoOptions.Database)
304→                .WithAadAzureTokenCredentialsAuthentication(this.tokenCredential!);
305→            return KustoClientFactory.CreateCslQueryProvider(kcsb);
306→        }
307→
308→        private IEnumerable<IReadOnlyList<string>> SplitStringBatches(IReadOnlyList<string> ids, int batchSize)
309→        {
310→            for (int i = 0; i < ids.Count; i += batchSize)
311→            {
312→                var count = Math.Min(batchSize, ids.Count - i);
313→                var batch = new List<string>(count);
314→                for (int j = 0; j < count; j++)
315→                {
316→                    batch.Add(ids[i + j]);
317→                }
318→
319→                yield return batch;
320→            }
321→        }
322→
323→        private string ResolveTokenScope(ServiceTreeKustoOptions options)
324→        {
325→            if (!string.IsNullOrWhiteSpace(options.TokenScope))
326→            {
327→                return options.TokenScope;
328→            }
329→
330→            if (Uri.TryCreate(options.ClusterUri, UriKind.Absolute, out var uri))
331→            {
332→                return $"{uri.GetLeftPart(UriPartial.Authority)}/.default";
333→            }
334→
335→            return string.Empty;
336→        }
337→
338→        private TokenCredential? ResolveTokenCredential(
339→            ICredentialFactory? credentialFactory,
340→            ServiceTreeClientOptions options)
341→        {
342→            // When ICredentialFactory is available AND auth mode is DefaultAzureCredential,
343→            // use the factory for cross-tenant support (PME MSI → MSFT tenant token).
344→            if (credentialFactory != null
345→                && options.AuthenticationMode == ServiceTreeAuthenticationMode.DefaultAzureCredential)
346→            {
347→                try
348→                {
349→                    var cred = credentialFactory.CreateTokenCredential(AADTenant.MSFT);
350→                    this.logger.LogInformation(
351→                        "ServiceTreeKustoClient: Using ICredentialFactory for MSFT-tenant credential (type={CredType}).",
352→                        cred.GetType().Name);
353→                    return cred;
354→                }
355→                catch (Exception ex)
356→                {
357→                    this.logger.LogError(
358→                        ex,
359→                        "ServiceTreeKustoClient: ICredentialFactory.CreateTokenCredential failed.");
360→                    throw;
361→                }
362→            }
363→
364→            return this.CreateTokenCredential(options);
365→        }
366→
367→        private TokenCredential? CreateTokenCredential(ServiceTreeClientOptions options)
368→        {
369→            if (options.AuthenticationMode == ServiceTreeAuthenticationMode.DefaultAzureCredential)
370→            {
371→                return new DefaultAzureCredential(new DefaultAzureCredentialOptions
372→                {
373→                    ManagedIdentityClientId = string.IsNullOrWhiteSpace(options.AadClientId) ? null : options.AadClientId,
374→                });
375→            }
376→
377→            if (options.AuthenticationMode == ServiceTreeAuthenticationMode.Aad)
378→            {
379→                if (!string.IsNullOrWhiteSpace(options.AadClientSecret)
380→                    && !string.IsNullOrWhiteSpace(options.AadTenantId)
381→                    && !string.IsNullOrWhiteSpace(options.AadClientId))
382→                {
383→                    return new ClientSecretCredential(options.AadTenantId, options.AadClientId, options.AadClientSecret);
384→                }
385→
386→                if (!string.IsNullOrWhiteSpace(options.AadClientCertificateBase64)
387→                    && !string.IsNullOrWhiteSpace(options.AadTenantId)
388→                    && !string.IsNullOrWhiteSpace(options.AadClientId))
389→                {
390→#pragma warning disable CA2000 // Certificate lifetime is tied to the credential.
391→                    var cert = this.LoadAadCertificate(options);
392→#pragma warning restore CA2000
393→
394→                    return new ClientCertificateCredential(
395→                        options.AadTenantId,
396→                        options.AadClientId,
397→                        cert,
398→                        new ClientCertificateCredentialOptions { SendCertificateChain = true });
399→                }
400→
401→                if (!string.IsNullOrWhiteSpace(options.AadClientId))
402→                {
403→                    return new ManagedIdentityCredential(options.AadClientId);
404→                }
405→
406→                return new ManagedIdentityCredential();
407→            }
408→
409→            return null;
410→        }
411→
412→        private string NormalizeIdentifier(string value)
413→        {
414→            if (string.IsNullOrWhiteSpace(value))
415→            {
416→                return value;
417→            }
418→
419→            var trimmed = value.Trim();
420→            return trimmed.All(ch => char.IsLetterOrDigit(ch) || ch == '_' || ch == '.')
421→                ? trimmed
422→                : trimmed.Replace("`", string.Empty, StringComparison.Ordinal);
423→        }
424→
425→        private int TryGetOrdinal(IDataReader reader, string name)
426→        {
427→            try
428→            {
429→                return reader.GetOrdinal(name);
430→            }
431→            catch (IndexOutOfRangeException)
432→            {
433→                return -1;
434→            }
435→        }
436→
437→        private string ReadString(IDataReader reader, int ordinal)
438→        {
439→            if (ordinal < 0 || reader.IsDBNull(ordinal))
440→            {
441→                return string.Empty;
442→            }
443→
444→            var value = reader.GetValue(ordinal);
445→            return value?.ToString() ?? string.Empty;
446→        }
447→
448→        private X509Certificate2 LoadAadCertificate(ServiceTreeClientOptions options)
449→        {
450→            try
451→            {
452→                var raw = Convert.FromBase64String(options.AadClientCertificateBase64);
453→                return new X509Certificate2(raw, options.AadClientCertificatePassword, X509KeyStorageFlags.MachineKeySet | X509KeyStorageFlags.EphemeralKeySet);
454→            }
455→            catch (FormatException ex)
456→            {
457→                this.logger.LogError(ex, "ServiceTreeKustoClient: failed to load AAD certificate from base64.");
458→                throw;
459→            }
460→            catch (CryptographicException ex)
461→            {
462→                this.logger.LogError(ex, "ServiceTreeKustoClient: failed to load AAD certificate from base64.");
463→                throw;
464→            }
465→        }
466→    }
467→
468→#pragma warning restore CA1303
469→}
