212→        {
213→            this.logger.LogInformation("SubmitConfigChangeSetAsync called");
214→            var authValidationResult = await this.configChangeValidator.CheckConfigChangeSetAuthorizationAsync(changeSet, this.User);
215→            if (!authValidationResult.Result)
216→            {
217→                this.logger.LogInformation("SubmitConfigChangeSetAsync no permisison");
218→                throw new UserException($"Authorization error: {authValidationResult.ErrorMessage}");
219→            }
220→
221→            var validationResult = await this.configChangeValidator.ValidateConfigChangeSetAsync(changeSet, this.User);
222→            if (!validationResult.Result)
223→            {
224→                this.logger.LogInformation("SubmitConfigChangeSetAsync validation failed");
225→                throw new UserException(validationResult.ErrorMessage);
226→            }
227→
228→            var userEmail = PermissionHelper.GetEmail(this.User);
229→            var displayName = PermissionHelper.GetFullDisplayName(this.User);
230→            return await this.configSvc.SubmitConfigChangeSetAsync(changeSet, displayName, userEmail).ConfigureAwait(false);
231→        }
